-- BLOCO 1 (parte 4/6) — Revisão linguística pílulas PIV (4 variants pt-BR)

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Sei o que é certo. E carrego o peso de agir nisso.", "tension_label": "Clareza ↔ Ação"}, "m2": {"scene": "Eduardo, 42, gere um time há seis anos. Sabe — com certeza absoluta — que uma pessoa precisa sair. Não porque é ruim no trabalho. Porque o papel não cabe mais nela. Tem visto a exaustão crescer semana a semana. Sabe que a conversa vai ser dura. Sabe que pode estragar a relação. Está sentado com esse saber há três meses. O time está notando a tensão. O sono dele está pior. É terça de manhã, 8:47, e ele olha pro calendário onde o nome dela aparece numa reunião das 9.", "question": "O que você acha que Eduardo vai fazer hoje? E qual vai ser a parte mais difícil — pra ele — do que quer que escolha?"}, "m4": {"question": "Agora — o que está entre sua clareza e sua ação? É dúvida, peso, outras pessoas, ou algo que você ainda não nomeou?", "instruction": "Uma frase. Nomeie o que está nesse espaço — dúvida, peso, alguém específico, ou algo ainda sem nome."}, "m3_1": {"context": "", "question": "Quando você sabe o que é certo mas o custo te deixa inseguro, você age primeiro (vai pra cima da situação) ou se recolhe primeiro (vira pra dentro pra entender)?", "pole_left": "Agir primeiro", "pole_right": "Entender primeiro"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Ajo. O custo de esperar é maior.", "followup": "O que você abre mão — e quem mais é afetado?", "followup_type": "cost"}, {"key": "B", "text": "Espero. Não estou pronto.", "followup": "O que você abre mão — e quem mais é afetado?", "followup_type": "cost"}, {"key": "C", "text": "Dou um passo menor primeiro.", "followup": "O que você está testando ao não ir até o fim?", "followup_type": "question"}, {"key": "D", "text": "Nomeio o conflito em voz alta.", "followup": "Pra quem você está falando, e qual o resultado que você espera?", "followup_type": "question"}], "scenario": "Você sabe o que precisa ser feito. Sabe há um tempo. O custo de agir está claro. O custo de esperar também. Você está no ponto de decisão."}, "m3_3": {"q1": "Lembre de uma vez em que você de fato agiu em algo que sabia ser certo, mesmo o custo sendo real. Qual era a situação? (Seja específico: quem estava envolvido, o que você fez, quando foi.)", "q2": "O que tornou possível agir? O que estava diferente naquele dia ou naquela situação — não na clareza, mas na sua capacidade de carregar o peso?", "scoring_note": "", "q_transversal": "Quando você agiu — o que você fez correspondeu ao que sua clareza pedia, ou a realidade forçou uma régua mais baixa?"}}$rdwth_final$::jsonb
WHERE id = 'dd1f8a98-5451-4cd9-9200-d04d17e11fac';

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "A resposta está clara pra mim. O custo de viver isso é mais pesado do que esperava.", "tension_label": "Clareza ↔ Ação"}, "m2": {"scene": "Beatriz, 34, concordou em ir no aniversário da mãe no sábado. Ela sabe — no momento em que disse sim — que não devia ter aceitado. Tem pesquisa pra terminar. Precisa desse fim de semana. Mas a mãe pediu pouca coisa. Três horas de carro. Quatro horas de jantar do qual ela não vai gostar. Já imaginou a conversa com o parceiro: 'Eu sei que disse sim. Sei o que eu deveria fazer. Só não consigo.' É quinta. A viagem é em 36 horas. Está mandando mensagens, tentando achar saída que não machuque, sabendo que não tem.", "question": "Qual é a escolha que Beatriz está encarando? E se ela ficar em casa, o que vai estar carregando?"}, "m4": {"question": "Conforme você respondia essas perguntas, percebeu se estava carregando o custo sozinho — ou procurando alguém pra dividir? O que isso te diz?", "instruction": "Uma frase ou duas. Descreva o que você de fato fez agora — não o que acha que deveria fazer."}, "m3_1": {"context": "", "question": "Quando você sabe o que precisa fazer mas o peso de agir é grande, tende a resolver logo ou esperar assentar?", "pole_left": "Resolver rápido", "pole_right": "Esperar assentar"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Ajo mesmo sendo pesado, porque o custo de não agir é maior.", "followup": "O que você abre mão — e quem mais é afetado?", "followup_type": "cost"}, {"key": "B", "text": "Deixo o peso assentar antes de me mover — entendo o que ele me diz sobre a escolha.", "followup": "O que o peso te ensinaria se você ficasse com ele?", "followup_type": "question"}, {"key": "C", "text": "Me movo de lado — mudo algo menor enquanto junto força pro movimento maior.", "followup": "O que você está aprendendo sobre sua capacidade enquanto faz isso?", "followup_type": "question"}, {"key": "D", "text": "Torno público: conto pras pessoas que estou lutando com isso.", "followup": "O que muda pra você quando para de carregar isso sozinho?", "followup_type": "question"}], "scenario": "Você vê o caminho certo com clareza. Já imaginou o primeiro passo. Mas em algum lugar entre saber e mover, sente peso — não incerteza, peso. Você entende o que agir vai custar. Também entende o que ficar parado vai custar. E hoje, tem que escolher com qual custo consegue conviver."}, "m3_3": {"q1": "Lembre de uma vez específica em que agiu sabendo o que era certo, mesmo sabendo o que ia te custar — em relação, tempo, conforto, reputação. O que aconteceu?", "q2": "O que mudou em você antes que fez o custo parecer suportável? Foi algo que você fez pra preparar, alguém que consultou, uma reformulação que fez, ou outra coisa?", "scoring_note": "", "q_transversal": "Olhando pra como você agiu — o que você fez ficou à altura da sua clareza, ou o peso fez você cortar?"}}$rdwth_final$::jsonb
WHERE id = '3ce805a7-c744-4b31-9f84-4934f1a424b1';

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Vejo o que precisa acontecer. O peso não está na visão — está no passo.", "tension_label": "Clareza ↔ Ação"}, "m2": {"scene": "Rafael, 38, toca um pequeno negócio. Sabe exatamente o que precisa fazer pra crescer mais rápido: contratar alguém, montar o sistema, escalar a receita. Vê com clareza. Também vê que a margem vai apertar por seis meses. Vê o risco. Sabe que precisaria conversar com a esposa antes — não pra pedir permissão (sempre disseram que ele não precisa), mas porque o impacto na casa é real. Vê a escolha: agir no que sabe que funciona, ou continuar como está. Não está travado na decisão em si. Está travado em outra coisa — algo sobre o que ele perderia se agisse. Faz cinco semanas que ele caminha as mesmas duas quadras toda manhã pensando nisso.", "question": "Do que você acha que Rafael está com medo de perder? E isso muda o que ele deveria fazer?"}, "m4": {"question": "Quando você se imaginou nessas situações, prestou mais atenção em quão certa era a ação ou no que ela ia custar? Qual puxou mais forte?", "instruction": "Escolha um. Em uma frase. O que pesou mais?"}, "m3_1": {"context": "", "question": "Em situações onde você está claro sobre a escolha certa mas consciente do custo real, tende a pesar mais a certeza (o quão certa é a escolha) ou o custo (o que vai mudar como consequência)?", "pole_left": "Pesar a certeza", "pole_right": "Pesar o custo"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Pago a conta inteira — ajo no que vejo, aceito o custo.", "followup": "O que você abre mão — e quem mais é afetado?", "followup_type": "cost"}, {"key": "B", "text": "Examino por que estou resistindo — não para evitar a ação, mas para entender o que a resistência protege.", "followup": "Que parte de você está dizendo não, e do que essa parte precisa?", "followup_type": "question"}, {"key": "C", "text": "Suavizo a clareza — busco uma versão da resposta que custe menos.", "followup": "Você está negociando consigo mesmo, e se sim, o que está tentando proteger?", "followup_type": "question"}, {"key": "D", "text": "Ajo, mas levo alguém comigo na ação.", "followup": "Quem, e o que você acha que essa pessoa consegue absorver que você não consegue?", "followup_type": "question"}], "scenario": "A clareza está aí. Não é o que você queria ouvir, mas é clara. E vem com uma conta. Você poderia evitar pagar fingindo que não vê. Pagar e acabar logo. Pagar uma versão menor. Ficar no ver sem agir ainda. Essas são suas opções reais."}, "m3_3": {"q1": "Lembre de um momento em que você sabia exatamente o que precisava acontecer E agiu nisso, mesmo sendo custoso. O que estava em jogo, e o que você fez?", "q2": "Olhando para trás, houve um momento em que passou de saber para se mover? O que aconteceu nessa transição? O que te deu permissão para agir?", "scoring_note": "", "q_transversal": "Quando você passou de saber pra fazer — o que você fez ficou à altura do que sabia?"}}$rdwth_final$::jsonb
WHERE id = '75e6958d-776d-491d-809d-750c8eed2504';

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Saber e fazer não são a mesma coisa. Sei disso agora porque estou vivendo a diferença.", "tension_label": "Clareza ↔ Ação"}, "m2": {"scene": "Cláudia, 45, está numa reunião de trabalho onde o time vai tomar uma decisão que ela acredita estar errada. Sabe os dados. Já viu isso antes. Consegue ver onde isso vai dar. Também sabe que falar significa uma de três coisas: vai ser passada por cima e vai se sentir impotente, vai ser ouvida e o sucesso vai pertencer a todos, ou vai criar tensão que ela vai ter que gerenciar. Vê as três. Também vê o custo do silêncio. A sala está em silêncio. Alguém acabou de pedir input. A mão dela está sobre a mesa.", "question": "O que Cláudia vai fazer, e o que ela está decidindo — sobre a decisão ou sobre si mesma?"}, "m4": {"question": "Algo em você sabe o que fazer. Outra coisa em você está segurando. Agora — qual delas parece mais você?", "instruction": "Nomeie qual em uma frase. Não tente reconciliar — só diga qual parece mais você agora."}, "m3_1": {"context": "", "question": "Quando carrega o peso de agir no que sabe ser certo, você prefere conversar com alguém pra dar sentido, ou decidir sozinho na sua cabeça?", "pole_left": "Conversando com alguém", "pole_right": "Decidindo sozinho"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Atravesso o limite — a clareza é permissão suficiente pra agir.", "followup": "O que você abre mão — e quem mais é afetado?", "followup_type": "cost"}, {"key": "B", "text": "Pratico a ação em escala pequena primeiro — faço uma vez de forma contida pra ver como sente.", "followup": "O que a versão pequena te ensinaria antes de você se comprometer com a inteira?", "followup_type": "question"}, {"key": "C", "text": "Ajo, mas de forma limitada — testo, vou devagar, reservo o direito de mudar de curso.", "followup": "O que precisaria pra você agir sem essa reserva?", "followup_type": "question"}, {"key": "D", "text": "Examino o que o limite em si está pedindo — não se atravessar, mas pra onde estou atravessando.", "followup": "O que vai estar diferente do outro lado?", "followup_type": "question"}], "scenario": "Você passou tempo com a resposta. Ela não mudou. Você checou contra seus valores, seus medos, suas obrigações. A clareza está sólida. Mas agir numa solidez que vai mudar coisas — isso cria um tipo específico de pressão. Você não está confuso sobre o que fazer. Está no limite de fazer."}, "m3_3": {"q1": "Descreva uma situação em que você carregou o peso de agir em algo que estava claro pra você. Qual era a situação, e qual era o peso especificamente?", "q2": "Que recursos — internos ou externos — você tinha acesso que te permitiram carregar? O que teria tornado impossível?", "scoring_note": "", "q_transversal": "Que recursos te permitiram agir num nível que correspondia à sua clareza? O que teria feito a ação ficar abaixo disso?"}}$rdwth_final$::jsonb
WHERE id = '5492404a-c1fd-46ea-a375-41fd02d05d48';